/**
 * Summary of platform-wide analytics.
 */
export interface AnalyticsSummary {
  totalUsers: number;
  totalOrders: number;
  revenue: number;
  activeUsers: number;
}

/**
 * Per-user analytics breakdown.
 */
export interface UserAnalytics {
  userId: string;
  orderCount: number;
  totalSpent: number;
  lastActive: Date;
}

/**
 * A single data point in a time-series trend.
 */
export interface TrendPoint {
  timestamp: Date;
  metric: string;
  value: number;
}

/**
 * Analytics service — aggregates data from users and orders
 * to provide dashboard-level insights.
 *
 * Depends on:
 * - UserRepository (data layer) for user counts and activity
 * - OrderRepository (data layer) for order and revenue data
 */

import type { AnalyticsSummary, UserAnalytics, TrendPoint } from '../models/analytics.js';
import type { UserRepository } from '../repositories/user.repository.js';
import type { OrderRepository } from '../repositories/order.repository.js';
import { Logger } from '../utils/logger.js';

export class AnalyticsService {
  private logger = new Logger('AnalyticsService');

  constructor(
    private userRepository: UserRepository,
    private orderRepository: OrderRepository,
  ) {}

  /**
   * Get a platform-wide analytics summary.
   */
  getSummary(): AnalyticsSummary {
    this.logger.info('Generating analytics summary');

    const totalUsers = this.userRepository.count();
    const orders = this.orderRepository.findAll();
    const totalOrders = orders.length;
    const revenue = orders.reduce((sum, order) => sum + order.total, 0);

    // Active users are those who have placed at least one order
    const userIdsWithOrders = new Set(orders.map((order) => order.userId));
    const activeUsers = userIdsWithOrders.size;

    return { totalUsers, totalOrders, revenue, activeUsers };
  }

  /**
   * Get analytics for a specific user.
   */
  getUserAnalytics(userId: string): UserAnalytics {
    this.logger.info(`Generating analytics for user: ${userId}`);

    const user = this.userRepository.findById(userId);
    if (!user) {
      throw new Error(`User not found: ${userId}`);
    }

    const orders = this.orderRepository.findByUserId(userId);
    const orderCount = orders.length;
    const totalSpent = orders.reduce((sum, order) => sum + order.total, 0);

    // lastActive is the most recent order date, or user creation date if no orders
    const lastActive = orders.length > 0
      ? orders.reduce((latest, order) =>
          order.createdAt > latest ? order.createdAt : latest, orders[0]!.createdAt)
      : user.createdAt;

    return { userId, orderCount, totalSpent, lastActive };
  }

  /**
   * Get time-series trend data for a metric within a date range.
   */
  getTrends(metric: string, startDate: Date, endDate: Date): TrendPoint[] {
    this.logger.info(`Generating trends for metric: ${metric} from ${startDate.toISOString()} to ${endDate.toISOString()}`);

    if (metric === 'orders') {
      return this.getOrderTrends(startDate, endDate);
    }

    if (metric === 'revenue') {
      return this.getRevenueTrends(startDate, endDate);
    }

    if (metric === 'users') {
      return this.getUserTrends(startDate, endDate);
    }

    throw new Error(`Unknown metric: ${metric}`);
  }

  private getOrderTrends(startDate: Date, endDate: Date): TrendPoint[] {
    const orders = this.orderRepository.findAll(
      (order) => order.createdAt >= startDate && order.createdAt <= endDate,
    );

    return this.aggregateByDay(orders, 'orders', (dayOrders) => dayOrders.length);
  }

  private getRevenueTrends(startDate: Date, endDate: Date): TrendPoint[] {
    const orders = this.orderRepository.findAll(
      (order) => order.createdAt >= startDate && order.createdAt <= endDate,
    );

    return this.aggregateByDay(orders, 'revenue', (dayOrders) =>
      dayOrders.reduce((sum, order) => sum + order.total, 0),
    );
  }

  private getUserTrends(startDate: Date, endDate: Date): TrendPoint[] {
    const users = this.userRepository.findAll(
      (user) => user.createdAt >= startDate && user.createdAt <= endDate,
    );

    return this.aggregateByDay(users, 'users', (dayUsers) => dayUsers.length);
  }

  private aggregateByDay<T extends { createdAt: Date }>(
    items: T[],
    metric: string,
    aggregator: (dayItems: T[]) => number,
  ): TrendPoint[] {
    const grouped = new Map<string, T[]>();

    for (const item of items) {
      const dayKey = item.createdAt.toISOString().split('T')[0]!;
      const existing = grouped.get(dayKey) ?? [];
      existing.push(item);
      grouped.set(dayKey, existing);
    }

    const points: TrendPoint[] = [];
    for (const [day, dayItems] of grouped) {
      points.push({
        timestamp: new Date(day),
        metric,
        value: aggregator(dayItems),
      });
    }

    points.sort((a, b) => a.timestamp.getTime() - b.timestamp.getTime());
    return points;
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { OrderRepository } from '../../src/repositories/order.repository.js';
import { AnalyticsService } from '../../src/services/analytics.service.js';
import type { User } from '../../src/models/user.js';
import type { Order } from '../../src/models/order.js';

describe('AnalyticsService', () => {
  let db: Database;
  let userRepo: UserRepository;
  let orderRepo: OrderRepository;
  let service: AnalyticsService;

  beforeEach(() => {
    db = new Database();
    userRepo = new UserRepository(db);
    orderRepo = new OrderRepository(db);
    service = new AnalyticsService(userRepo, orderRepo);
  });

  function createUser(id: string, name: string, createdAt?: Date): User {
    const now = createdAt ?? new Date();
    const user: User = {
      id,
      name,
      email: `${name.toLowerCase()}@example.com`,
      role: 'member',
      createdAt: now,
      updatedAt: now,
    };
    userRepo.save(user);
    return user;
  }

  function createOrder(id: string, userId: string, total: number, createdAt?: Date): Order {
    const now = createdAt ?? new Date();
    const order: Order = {
      id,
      userId,
      items: [{ productId: 'p1', name: 'Item', quantity: 1, unitPrice: total }],
      total,
      status: 'pending',
      createdAt: now,
      updatedAt: now,
    };
    orderRepo.save(order);
    return order;
  }

  describe('getSummary', () => {
    it('should return zeros when no data exists', () => {
      const summary = service.getSummary();

      expect(summary.totalUsers).toBe(0);
      expect(summary.totalOrders).toBe(0);
      expect(summary.revenue).toBe(0);
      expect(summary.activeUsers).toBe(0);
    });

    it('should return correct totals', () => {
      createUser('u1', 'Alice');
      createUser('u2', 'Bob');
      createUser('u3', 'Charlie');
      createOrder('o1', 'u1', 100);
      createOrder('o2', 'u1', 50);
      createOrder('o3', 'u2', 200);

      const summary = service.getSummary();

      expect(summary.totalUsers).toBe(3);
      expect(summary.totalOrders).toBe(3);
      expect(summary.revenue).toBe(350);
      expect(summary.activeUsers).toBe(2);
    });

    it('should count active users by unique order userIds', () => {
      createUser('u1', 'Alice');
      createUser('u2', 'Bob');
      createOrder('o1', 'u1', 10);
      createOrder('o2', 'u1', 20);

      const summary = service.getSummary();

      expect(summary.activeUsers).toBe(1);
    });
  });

  describe('getUserAnalytics', () => {
    it('should throw for non-existent user', () => {
      expect(() => service.getUserAnalytics('nonexistent')).toThrow('User not found');
    });

    it('should return analytics for user with no orders', () => {
      const user = createUser('u1', 'Alice');
      const analytics = service.getUserAnalytics('u1');

      expect(analytics.userId).toBe('u1');
      expect(analytics.orderCount).toBe(0);
      expect(analytics.totalSpent).toBe(0);
      expect(analytics.lastActive).toEqual(user.createdAt);
    });

    it('should return correct analytics for user with orders', () => {
      createUser('u1', 'Alice');
      createOrder('o1', 'u1', 100, new Date('2025-01-10'));
      createOrder('o2', 'u1', 200, new Date('2025-03-15'));

      const analytics = service.getUserAnalytics('u1');

      expect(analytics.userId).toBe('u1');
      expect(analytics.orderCount).toBe(2);
      expect(analytics.totalSpent).toBe(300);
      expect(analytics.lastActive).toEqual(new Date('2025-03-15'));
    });

    it('should use most recent order date as lastActive', () => {
      createUser('u1', 'Alice');
      createOrder('o1', 'u1', 50, new Date('2025-06-01'));
      createOrder('o2', 'u1', 75, new Date('2025-01-01'));
      createOrder('o3', 'u1', 25, new Date('2025-03-01'));

      const analytics = service.getUserAnalytics('u1');

      expect(analytics.lastActive).toEqual(new Date('2025-06-01'));
    });
  });

  describe('getTrends', () => {
    it('should throw for unknown metric', () => {
      expect(() =>
        service.getTrends('unknown', new Date('2025-01-01'), new Date('2025-12-31')),
      ).toThrow('Unknown metric: unknown');
    });

    it('should return order trends grouped by day', () => {
      createUser('u1', 'Alice');
      createOrder('o1', 'u1', 100, new Date('2025-01-15T10:00:00Z'));
      createOrder('o2', 'u1', 200, new Date('2025-01-15T14:00:00Z'));
      createOrder('o3', 'u1', 50, new Date('2025-01-16T09:00:00Z'));

      const trends = service.getTrends('orders', new Date('2025-01-01'), new Date('2025-01-31'));

      expect(trends).toHaveLength(2);
      expect(trends[0]!.metric).toBe('orders');
      expect(trends[0]!.value).toBe(2); // 2 orders on Jan 15
      expect(trends[1]!.value).toBe(1); // 1 order on Jan 16
    });

    it('should return revenue trends grouped by day', () => {
      createUser('u1', 'Alice');
      createOrder('o1', 'u1', 100, new Date('2025-01-15T10:00:00Z'));
      createOrder('o2', 'u1', 200, new Date('2025-01-15T14:00:00Z'));
      createOrder('o3', 'u1', 50, new Date('2025-01-16T09:00:00Z'));

      const trends = service.getTrends('revenue', new Date('2025-01-01'), new Date('2025-01-31'));

      expect(trends).toHaveLength(2);
      expect(trends[0]!.metric).toBe('revenue');
      expect(trends[0]!.value).toBe(300); // $300 on Jan 15
      expect(trends[1]!.value).toBe(50);  // $50 on Jan 16
    });

    it('should return user registration trends grouped by day', () => {
      createUser('u1', 'Alice', new Date('2025-02-01T08:00:00Z'));
      createUser('u2', 'Bob', new Date('2025-02-01T12:00:00Z'));
      createUser('u3', 'Charlie', new Date('2025-02-02T10:00:00Z'));

      const trends = service.getTrends('users', new Date('2025-02-01'), new Date('2025-02-28'));

      expect(trends).toHaveLength(2);
      expect(trends[0]!.metric).toBe('users');
      expect(trends[0]!.value).toBe(2); // 2 users on Feb 1
      expect(trends[1]!.value).toBe(1); // 1 user on Feb 2
    });

    it('should filter by date range', () => {
      createUser('u1', 'Alice');
      createOrder('o1', 'u1', 100, new Date('2025-01-10'));
      createOrder('o2', 'u1', 200, new Date('2025-02-15'));
      createOrder('o3', 'u1', 50, new Date('2025-03-20'));

      const trends = service.getTrends('orders', new Date('2025-02-01'), new Date('2025-02-28'));

      expect(trends).toHaveLength(1);
      expect(trends[0]!.value).toBe(1);
    });

    it('should return empty array when no data in range', () => {
      createUser('u1', 'Alice');
      createOrder('o1', 'u1', 100, new Date('2025-06-01'));

      const trends = service.getTrends('orders', new Date('2025-01-01'), new Date('2025-01-31'));

      expect(trends).toHaveLength(0);
    });

    it('should return trends sorted by date', () => {
      createUser('u1', 'Alice');
      createOrder('o1', 'u1', 50, new Date('2025-01-20'));
      createOrder('o2', 'u1', 100, new Date('2025-01-10'));
      createOrder('o3', 'u1', 75, new Date('2025-01-15'));

      const trends = service.getTrends('revenue', new Date('2025-01-01'), new Date('2025-01-31'));

      expect(trends).toHaveLength(3);
      expect(trends[0]!.timestamp.getTime()).toBeLessThan(trends[1]!.timestamp.getTime());
      expect(trends[1]!.timestamp.getTime()).toBeLessThan(trends[2]!.timestamp.getTime());
    });
  });
});

